## Claude tool use
```typescript
const tools = [
  {
    name: "get_weather",
    description: "取得指定城市的天氣",
    input_schema: {
      type: "object",
      properties: {
        city: { type: "string", description: "城市名" },
      },
      required: ["city"],
    },
  },
  {
    name: "send_email",
    description: "寄 email",
    input_schema: {
      type: "object",
      properties: {
        to: { type: "string" },
        subject: { type: "string" },
        body: { type: "string" },
      },
      required: ["to", "subject", "body"],
    },
  },
];

const response = await client.messages.create({
  model: "claude-opus-4-7",
  max_tokens: 1024,
  tools,
  messages: [{ role: "user", content: "台北現在幾度？告訴我朋友" }],
});

// Claude 會回 tool_use block
if (response.content[0].type === "tool_use") {
  const { name, input } = response.content[0];
  if (name === "get_weather") {
    const weather = await fetchWeather(input.city);
    // 把結果再傳回去
    const finalResponse = await client.messages.create({
      model: "claude-opus-4-7",
      max_tokens: 1024,
      tools,
      messages: [
        { role: "user", content: "台北現在幾度？告訴我朋友" },
        { role: "assistant", content: response.content },
        {
          role: "user",
          content: [{
            type: "tool_result",
            tool_use_id: response.content[0].id,
            content: weather,
          }],
        },
      ],
    });
  }
}
```

